struct State {
    let cost: Int64
    let i: Int
    let j: Int
    let isOdd: Bool
}

struct Heap<T> {
    private var nodes: [T]
    private let sort: (T, T) -> Bool

    init(sort: @escaping (T, T) -> Bool) {
        self.nodes = []
        self.sort = sort
    }

    var isEmpty: Bool {
        return nodes.isEmpty
    }

    mutating func insert(_ element: T) {
        nodes.append(element)
        siftUp(nodes.count - 1)
    }

    mutating func remove() -> T? {
        guard !nodes.isEmpty else { return nil }
        let tmp = nodes[0]
        nodes[0] = nodes[nodes.count - 1]
        nodes.removeLast()
        siftDown(0)
        return tmp
    }

    private mutating func siftUp(_ index: Int) {
        var childIndex = index
        let child = nodes[childIndex]
        var parentIndex = (childIndex - 1) / 2

        while childIndex > 0 && sort(child, nodes[parentIndex]) {
            nodes[childIndex] = nodes[parentIndex]
            childIndex = parentIndex
            parentIndex = (childIndex - 1) / 2
        }
        nodes[childIndex] = child
    }

    private mutating func siftDown(_ index: Int) {
        let size = nodes.count
        var parentIndex = index

        while true {
            let leftChildIndex = 2 * parentIndex + 1
            let rightChildIndex = leftChildIndex + 1
            var candidate = parentIndex

            if leftChildIndex < size && sort(nodes[leftChildIndex], nodes[candidate]) {
                candidate = leftChildIndex
            }
            if rightChildIndex < size && sort(nodes[rightChildIndex], nodes[candidate]) {
                candidate = rightChildIndex
            }
            if candidate == parentIndex {
                return
            }
            nodes.swapAt(parentIndex, candidate)
            parentIndex = candidate
        }
    }
}

func solve(m: Int64, n: Int64, waitCost: [[Int64]]) -> Int64 {
    let m_i = Int(m)
    let n_i = Int(n)

    if m_i == 1 && n_i == 1 {
        return 1
    }

    let INF: Int64 = 1000000000000000000
    var dist_odd = [[Int64]](repeating: [Int64](repeating: INF, count: n_i), count: m_i)
    var dist_even = [[Int64]](repeating: [Int64](repeating: INF, count: n_i), count: m_i)

    var heap = Heap<State>(sort: { $0.cost < $1.cost })
    let directions = [(1, 0), (0, 1)]

    for (dx, dy) in directions {
        let ni = 0 + dx
        let nj = 0 + dy
        if ni < m_i && nj < n_i {
            let entryCost = Int64(ni + 1) * Int64(nj + 1)
            let totalCost = 1 + entryCost
            if totalCost < dist_odd[ni][nj] {
                dist_odd[ni][nj] = totalCost
                heap.insert(State(cost: totalCost, i: ni, j: nj, isOdd: true))
            }
        }
    }

    while !heap.isEmpty {
        guard let state = heap.remove() else { break }
        let (cost, i, j, isOdd) = (state.cost, state.i, state.j, state.isOdd)

        if isOdd {
            if cost != dist_odd[i][j] { continue }
        } else {
            if cost != dist_even[i][j] { continue }
        }

        if isOdd && i == m_i - 1 && j == n_i - 1 {
            return cost
        }

        if isOdd {
            let nextCost = cost + waitCost[i][j]
            if nextCost < dist_even[i][j] {
                dist_even[i][j] = nextCost
                heap.insert(State(cost: nextCost, i: i, j: j, isOdd: false))
            }
        } else {
            for (dx, dy) in directions {
                let ni = i + dx
                let nj = j + dy
                if ni < m_i && nj < n_i {
                    let entryCost = Int64(ni + 1) * Int64(nj + 1)
                    let totalCost = cost + entryCost
                    if totalCost < dist_odd[ni][nj] {
                        dist_odd[ni][nj] = totalCost
                        heap.insert(State(cost: totalCost, i: ni, j: nj, isOdd: true))
                    }
                }
            }
        }
    }

    return INF
}
```

### Explanation
1. **Initialization**:
   - The solution checks if the grid is 1x1 and immediately returns the entry cost (1) since no movement is needed.
   - Two 2D arrays, `dist_odd` and `dist_even`, are initialized to store the minimum costs for each cell when reached during an odd or even second, respectively.
   - A min-heap (priority queue) is used to process states in order of increasing cost.

2. **Processing Initial Moves**:
   - From the starting cell (0, 0), the algorithm explores moving to the right (0, 1) and down (1, 0) during the first second (odd). The total cost for these moves includes the entry cost of (0, 0) and the entry cost of the new cell.

3. **Dijkstra's Algorithm**:
   - The algorithm processes each state from the heap. If the state is the target cell (m-1, n-1) during an odd second, the cost is returned.
   - **Odd State Handling**: Transitions to an even state by waiting in the current cell, updating the cost with the waiting cost.
   - **Even State Handling**: Moves to adjacent cells (right or down) during the next odd second, updating the cost with the new cell's entry cost.

4. **Termination**:
   - The algorithm ensures the shortest path is found by always processing the lowest-cost state first. If the heap is exhausted without reaching the target, it returns a large value (though a path is guaranteed to exist).

This approach efficiently explores the grid while respecting the alternating movement and waiting rules, ensuring the minimum cost path is found using Dijkstra's algorithm with state tracking for odd and even seconds.

To solve this problem, we need to find the minimum cost to travel from the top-left corner (0, 0) to the bottom-right corner (m-1, n-1) of a grid, following specific movement rules. The movement alternates between moving on odd steps and waiting on even steps, with costs associated with entering cells and waiting in cells.

### Approach
1. **Problem Analysis**: 
   - **Movement Rules**: On odd steps (1st, 3rd, etc.), you must move right or down to an adjacent cell and pay the entrance cost. On even steps (2nd, 4th, etc.), you must wait in the current cell for one second, paying the waiting cost.
   - **Cost Calculation**: The entrance cost for cell (i, j) is (i+1)*(j+1), and the waiting cost is given by `waitCost[i][j]`.

2. **Intuition**:
   - **State Representation**: The state of the traveler is represented by their position (i, j) and the next step's type (odd or even). This gives us states `(i, j, s)` where `s` is 0 (even step) or 1 (odd step).
   - **Dynamic Programming (DP)**: Use a DP table `dp[i][j][s]` to store the minimum cost to reach cell (i, j) with step type `s`.
   - **Priority Queue (Min-Heap)**: Efficiently explore the grid by always expanding the node with the current minimum cost. This ensures the first time we reach the destination, it is with the minimum cost.

3. **Algorithm**:
   - **Initialization**: Start at (0, 0) with step type 1 (odd), setting the cost to the entrance cost (1*1 = 1).
   - **Priority Queue Handling**: 
     - **Move (s=1)**: From cell (i, j), move right or down to adjacent cells, updating the DP state for the new cell with step type 0 (even).
     - **Wait (s=0)**: Pay the waiting cost in the current cell, transitioning to step type 1 (odd).
   - **Termination**: The minimum cost to reach (m-1, n-1) is the minimum of the costs in step types 0 and 1 at this cell.

4. **Complexity Analysis**:
   - **Time Complexity**: O(m*n*log(m*n)) since each cell is processed up to twice (for step types), and priority queue operations take logarithmic time.
   - **Space Complexity**: O(m*n*2) for the DP table and priority queue.

