func solve(m: Int64, n: Int64, waitCost: Array<Array<Int64>>) -> Int64 {
    let INF: Int64 = 1_000_000_000_000_000_000
    let MI = Int(m)
    let NJ = Int(n)
    var dp = Array<Array<Array<Int64>>>()
    for i in 0..<MI {
        var row = Array<Array<Int64>>()
        for j in 0..<NJ {
            row.append([INF, INF])
        }
        dp.append(row)
    }
    dp[0][0][1] = 1
    var pq = [(Int64, Int, Int, Int)]()
    pq.append((1, 0, 0, 1))
    while !pq.isEmpty {
        var min_idx = 0
        var min_cost = pq[0].0
        for idx in 1..<pq.count {
            if pq[idx].0 < min_cost {
                min_cost = pq[idx].0
                min_idx = idx
            }
        }
        let (cost, i, j, s) = pq[min_idx]
        pq.remove(at: min_idx)
        if cost != dp[i][j][s] {
            continue
        }
        if s == 1 {
            if i+1 < MI {
                let ni = i+1
                let nj = j
                let ent = Int64(ni+1) * Int64(nj+1)
                let nc = cost + ent
                if nc < dp[ni][nj][0] {
                    dp[ni][nj][0] = nc
                    pq.append((nc, ni, nj, 0))
                }
            }
            if j+1 < NJ {
                let ni = i
                let nj = j+1
                let ent = Int64(ni+1) * Int64(nj+1)
                let nc = cost + ent
                if nc < dp[ni][nj][0] {
                    dp[ni][nj][0] = nc
                    pq.append((nc, ni, nj, 0))
                }
            }
        } else {
            let nc = cost + waitCost[i][j]
            if nc < dp[i][j][1] {
                dp[i][j][1] = nc
                pq.append((nc, i, j, 1))
            }
        }
    }
    let ans = min(dp[MI-1][NJ-1][0], dp[MI-1][NJ-1][1])
    return ans
}
```

### Explanation
1. **Initialization**: The DP table `dp` is initialized to store the minimum costs for each cell and step type (even or odd). The start cell (0, 0) is initialized for step type 1 (odd) with the entrance cost (1).
2. **Priority Queue (PQ)**: The PQ processes nodes in order of increasing cost. For each node, if it's an odd step, it moves right or down, updating the cost for the new cell to an even step. If it's an even step, it waits, updating the cost for the same cell to an odd step.
3. **Termination**: The minimum cost to reach the destination (m-1, n-1) is the lesser of the costs associated with arriving on an even or odd step at the destination, stored in `dp`.

This approach efficiently explores all possible paths while minimizing the total cost by leveraging dynamic programming and a priority queue for optimal path selection.
